def nested_lookup(data, keys):
    current = data
    for key in keys:
        try:
            current = current[key]
        except KeyError:
            print(f"Missing key: {key}")
            return
        except TypeError:
            print(f"Not a dict at key: {key}")
            return
    print(f"Found: {current}")

config = {"db": {"host": "localhost", "port": 5432}}
nested_lookup(config, ["db", "host"])
nested_lookup(config, ["db", "password"])
nested_lookup(config, ["db", "port", "value"])

