class BankError(Exception):
    pass

class InsufficientFundsError(BankError):
    def __init__(self, balance, amount):
        self.balance = balance
        self.amount = amount
        super().__init__(f"Cannot withdraw ${amount}, only ${balance} available")

class InvalidAmountError(BankError):
    pass

def transfer(balance, amount):
    if amount <= 0:
        raise InvalidAmountError(f"Invalid amount: ${amount}")
    if amount > balance:
        raise InsufficientFundsError(balance, amount)
    print(f"Transferred: ${amount}, remaining: ${balance - amount}")

for args in [(1000, 500), (1000, -50), (100, 500)]:
    try:
        transfer(*args)
    except BankError as e:
        print(f"{type(e).__name__}: {e}")

class ConfigError(Exception):
    pass

class MissingKeyError(ConfigError):
    def __init__(self, key):
        self.key = key
        super().__init__(f"Missing required key: '{key}'")

class InvalidValueError(ConfigError):
    def __init__(self, key, value):
        self.key = key
        self.value = value
        super().__init__(f"Invalid value for '{key}': {value!r}")

def validate_config(config):
    for key in ['host', 'port']:
        if key not in config:
            raise MissingKeyError(key)
    if not isinstance(config['host'], str):
        raise InvalidValueError('host', config['host'])
    if not isinstance(config['port'], int):
        raise InvalidValueError('port', config['port'])
    if not (1 <= config['port'] <= 65535):
        raise InvalidValueError('port', config['port'])
    print(f"Config valid: {config['host']}:{config['port']}")

configs = [
    {'host': 'localhost', 'port': 8080},
    {'host': 'localhost'},
    {'host': 'localhost', 'port': 'abc'}
]
for cfg in configs:
    try:
        validate_config(cfg)
    except ConfigError as e:
        print(f"{type(e).__name__}: {e}")

class HTTPError(Exception):
    status_code = 0
    def __init__(self, message=""):
        self.message = message
        super().__init__(f"HTTP {self.status_code}: {message}")

class NotFoundError(HTTPError):
    status_code = 404

class ForbiddenError(HTTPError):
    status_code = 403

class ServerError(HTTPError):
    status_code = 500

def handle_response(code):
    errors = {404: NotFoundError, 403: ForbiddenError, 500: ServerError}
    if code in errors:
        raise errors[code](f"Response code {code}")
    print(f"OK: {code}")

for code in [200, 404, 403, 500]:
    try:
        handle_response(code)
    except HTTPError as e:
        print(f"{type(e).__name__} (status {e.status_code}): {e}")

