import traceback

def inner():
    raise ValueError("something broke")

def middle():
    inner()

def outer():
    try:
        middle()
    except ValueError:
        tb_string = traceback.format_exc()
        lines = tb_string.strip().split('\n')
        print(f"Error chain has {len(lines)} lines")
        print(f"First line: {lines[0]}")
        print(f"Last line: {lines[-1]}")

outer()

