def create_matrix(rows, cols, fill=0):
    assert isinstance(rows, int) and rows > 0, f"rows must be positive int, got {rows}"
    assert isinstance(cols, int) and cols > 0, f"cols must be positive int, got {cols}"
    matrix = [[fill] * cols for _ in range(rows)]
    assert len(matrix) == rows, "Row count mismatch"
    assert all(len(row) == cols for row in matrix), "Column count mismatch"
    return matrix

try:
    result = create_matrix(2, 3, 1)
    for row in result:
        print(row)
except AssertionError as e:
    print(f"Assertion failed: {e}")

try:
