def inspect_and_sum(items):
    total = 0.0
    processed = 0
    for i, item in enumerate(items):
        print(f"  [{i}] type={type(item).__name__}, repr={item!r}")
        try:
            total += float(item)
            processed += 1
        except (ValueError, TypeError):
            print(f"  Skipping: {item!r}")
    print(f"Total: {total}")
    print(f"Processed: {processed}/{len(items)}")

inspect_and_sum([10, '20.5', None, 30, 'abc'])
